Method.Source:
    [Form]
    public class ETGLogisticsAddressRuralMuncipalityLookupCopy extends FormRun
    {
        LogisticsAddressCityRecId           cityRecId;
        LogisticsAddressCountryRegionId     countryRegionId;
        LogisticsAddressStateId             stateId;
        LogisticsAddressCountyId            countyId;

        FormStringControl                   lookupControl;       
        LogisticsPostalAddressMap           callerLogisticsAddressMap;
        boolean                             callerHasLogisticsAddressMap;    // Tells if caller data source is compatible with LogisticsAddressMap.
                                                    // Used in cases where LogisticsAddress record is created but not yet saved.

        LogisticsAddressZipCode             zipCodeRecord;
}

public void closeSelect(str _selectString)
{
    if (!_selectString)
    {
        super(_selectString);
        return;
    }

    if (callerHasLogisticsAddressMap)
    {
        callerLogisticsAddressMap.LogisticsPostalAddressMap::initFromDistrict(logisticsAddressDistrict);
    }
    else if (zipCodeRecord)
    {
        zipCodeRecord.District = logisticsAddressDistrict.RecId;
    }

    super(_selectString);

    if (callerHasLogisticsAddressMap && FormDataUtil::getFormDataSource(callerLogisticsAddressMap) != null)
    {
        // Refresh the caller form data source to update LogisticsAddress fields.
        FormDataUtil::getFormDataSource(callerLogisticsAddressMap).refresh();
    }
}

void init()
{
    FormRun     callerFormRun;

    if (element.args() != null &&
        typeOf(element.args().record()) != typeOf(null) &&
        SysDictTable::isTableMapped(tableNum(LogisticsPostalAddressMap), element.args().record().TableId))
    {
        // Record type is checked against null as defaulting should still
        // occur on non-persisted records which do not yet have a recid

        // Save the caller data source to update its LogisticsAddress information later.
        callerLogisticsAddressMap = element.args().record();
        // Remember that caller has data source compatible with the LogisticsAddressMap map.
        callerHasLogisticsAddressMap = true;
        element.setCityRecId(callerLogisticsAddressMap.CityRecId);
    }
    else if (element.args().dataset() == tableNum(LogisticsAddressZipCode))
    {
        zipCodeRecord = element.args().record();
        element.setCityRecId(zipCodeRecord.CityRecId);

        if(!cityRecId)
        {
            element.setCountryRegionID(zipCodeRecord.CountryRegionId);
            element.setStateID(zipCodeRecord.State);
            element.setCountyID(zipCodeRecord.County);
        }
    }
    else
    {
        callerHasLogisticsAddressMap = false;
    }

    super();

    if (element.args().caller())
    {
        callerFormRun   = element.args().caller();
        lookupControl   = SysTableLookup::getCallerStringControl(element.args());
    }

    if (this.lookupControlHasWildcard())
    {
        logisticsAddressDistrict_ds.query().dataSourceTable(tableNum(LogisticsAddressDistrict)).addRange(fieldNum(LogisticsAddressDistrict, Name)).value(lookupControl.text());
    }

    element.selectMode(district_Name);
}

private boolean lookupControlHasWildcard()
{
    return lookupControl && strFind(lookupControl.text(), '*', 1, strLen(lookupControl.text()));
}

public void run()
{       
    boolean         filterLookup    = false;

    if (!lookupControl)
    {
        super();
        return;
    }        

    filterLookup = SysTableLookup::filterLookupPreRun(lookupControl, district_Name, logisticsAddressDistrict_ds);

    super();

    SysTableLookup::filterLookupPostRun(filterLookup, lookupControl.text(), district_Name, logisticsAddressDistrict_ds);


    if (callerHasLogisticsAddressMap)
    {
        if (!this.lookupControlHasWildcard())
        {
            if (lookupControl)
            {
                callerLogisticsAddressMap.DistrictName = lookupControl.text();
            }

            if (lookupControl && lookupControl.text())
            {
                logisticsAddressDistrict_ds.object(fieldNum(LogisticsAddressDistrict, Name)).filter(lookupControl.text() + '*');
            }
        }

        if (lookupControl && (!lookupControl.text()|| this.lookupControlHasWildcard()))
        {
            if (callerLogisticsAddressMap.CityRecId)
            {
                logisticsAddressDistrict_ds.object(fieldNum(LogisticsAddressDistrict, City)).filter(queryValue(callerLogisticsAddressMap.CityRecId));
            }
        }

    }       

}

void init()
{
    Query                   query = new Query();
    QueryBuildDataSource    queryBuildCityDataSource, queryBuildDistrictDataSource;

    super();

    queryBuildDistrictDataSource = query.addDataSource(tableNum(LogisticsAddressDistrict));

    if(cityRecId != 0)
    {
        queryBuildDistrictDataSource.addRange(fieldNum(LogisticsAddressDistrict, City)).value(queryValue(cityRecId));
    }
    else
    {
        queryBuildCityDataSource = queryBuildDistrictDataSource.addDataSource(tableNum(LogisticsAddressCity));
        queryBuildCityDataSource.joinMode(JoinMode::ExistsJoin);
        queryBuildCityDataSource.relations(true);

        if(countryRegionId != '')
        {
            queryBuildCityDataSource.addRange(fieldNum(LogisticsAddressCity, CountryRegionId)).value(queryValue(countryRegionId));
        }

        if(stateId != '')
        {
            queryBuildCityDataSource.addRange(fieldNum(LogisticsAddressCity, StateId)).value(queryValue(stateId));
        }

        if(countyId != '')
        {
            queryBuildCityDataSource.addRange(fieldNum(LogisticsAddressCity, CountyId)).value(queryValue(countyId));
        }
    }

    this.query(query);
}
